SELECT SUM(construction_cost) AS total_construction_cost, AVG(construction_cost) AS average_construction_cost
FROM church_buildings
WHERE bldg_status = 'in use';

SELECT parish_id, COUNT(member_id) as member_count
FROM parish_members
GROUP BY parish_id;

SELECT COUNT(donation_id) AS total_donations, SUM(amount) AS total_amount
FROM parish_donations
WHERE donor_id = 1;

SELECT COUNT(*) AS num_final_reports
FROM parish_reports
WHERE report_status = 'final' AND parish_id = 0;

SELECT report_type, report_file_path
FROM parish_reports
WHERE parish_id = 0 AND report_status = 'final';

SELECT officer_name, email
FROM financial_officers
WHERE status = 'active';

SELECT COUNT(*) AS total_active_officers
FROM financial_officers
WHERE status = 'active';

SELECT COUNT(*) AS active_members_count
FROM parish_members
WHERE parish_id = 0 AND status = 'active';

SELECT parish_id, SUM(amount) AS total_donations
FROM parish_donations
GROUP BY parish_id;

SELECT event_name
FROM parish_events
WHERE event_cost > 5000;

SELECT note_text
FROM parish_notes
WHERE note_type = 'administrative' AND status = 'active';

SELECT church_name, parish_est_year
FROM parishes
ORDER BY parish_est_year ASC;

SELECT donation_date, amount
FROM parish_donations
WHERE donation_status = 'received';

SELECT member_name, member_type
FROM parish_members
WHERE parish_id = 1;
